const items = $input.all();

// Берем chat_id из parse choose topic
const parsed = $('parse choose topic').first().json;

const chatId = parsed.chat_id;
const userId = parsed.user_id;

// Создаем кнопки топиков
const buttons = items
  .filter(item => item.json.id && item.json.title)
  .map(item => ({
    text: `📁 ${item.json.title}`,
    callback_data: `select_topic:${item.json.id}`
  }));

// Кнопка создания нового топика
buttons.push({
  text: '➕ Create new topic',
  callback_data: 'action:create_new'
});

// Группируем по 2 кнопки в ряд
const rows = [];
while (buttons.length) {
  rows.push(buttons.splice(0, 2));
}

return [
  {
    json: {
      user_id: userId,
      chat_id: chatId,
      text: 'Choose a topic:',
      inline_keyboard: rows
    }
  }
];

