const items = $input.all();

const trigger = $('Telegram Trigger').first().json;

const fallbackChatId =
  trigger.callback_query?.message?.chat?.id ||
  trigger.callback_query?.from?.id ||
  trigger.message?.chat?.id ||
  trigger.message?.from?.id;

if (items.length === 0) {
  return [
    {
      json: {
        api_method: 'sendMessage',
        body: {
          chat_id: fallbackChatId,
          text: 'There are no messages in this topic yet. 📭'
        }
      }
    }
  ];
}

const first = items[0].json;
const topicTitle = String(first.topic_title || '').trim();
const isDeletedTopic = topicTitle.toLowerCase() === 'deleted messages';

const output = [];

if (isDeletedTopic) {
  output.push({
    json: {
      api_method: 'sendMessage',
      body: {
        chat_id: first.chat_id || fallbackChatId,
        text:
`⚠️ Messages in this folder will be deleted automatically.

If you want to keep something, please forward it back to this bot.`
      }
    }
  });
}

function deleteKeyboard(messageId) {
  if (isDeletedTopic || !messageId) {
    return undefined;
  }

  return {
    inline_keyboard: [
      [
        {
          text: '🗑 Delete',
          callback_data: `delete_msg:${messageId}`
        }
      ]
    ]
  };
}

function formatLocation(data) {
  const title = data.location_title ? `\n${data.location_title}` : '';
  const address = data.location_address ? `\n${data.location_address}` : '';

  const coords =
    data.latitude !== null &&
    data.latitude !== undefined &&
    data.longitude !== null &&
    data.longitude !== undefined
      ? `\nCoordinates: ${data.latitude}, ${data.longitude}`
      : '';

  const maps = data.maps_url ? `\nGoogle Maps: ${data.maps_url}` : '';

  return `📍 Location${title}${address}${coords}${maps}`.trim();
}

for (const item of items) {
  const data = item.json;

  const chatId = data.chat_id || fallbackChatId;
  const messageType = data.message_type || 'text';

  if (messageType === 'empty' || (!data.content && !data.file_id && messageType !== 'location')) {
    output.push({
      json: {
        api_method: 'sendMessage',
        body: {
          chat_id: chatId,
          text: isDeletedTopic
            ? 'Deleted messages folder is empty 📭'
            : 'There are no messages in this topic yet. 📭'
        }
      }
    });

    continue;
  }

  const keyboard = deleteKeyboard(data.id);

  // Location
  if (messageType === 'location') {
    const body = {
      chat_id: chatId,
      text: formatLocation(data),
      disable_web_page_preview: false
    };

    if (keyboard) {
      body.reply_markup = keyboard;
    }

    output.push({
      json: {
        api_method: 'sendMessage',
        body
      }
    });

    continue;
  }

  // Text
  if (messageType === 'text' || (!data.file_id && messageType !== 'location')) {
    const body = {
      chat_id: chatId,
      text: String(data.content || data.caption || '[empty message]').trim()
    };

    if (keyboard) {
      body.reply_markup = keyboard;
    }

    output.push({
      json: {
        api_method: 'sendMessage',
        body
      }
    });

    continue;
  }

  const displayName =
    data.file_name ||
    data.caption ||
    data.content ||
    (
      messageType === 'video_note'
        ? 'Video note'
        : `[${messageType}]`
    );

  // Photo
  if (messageType === 'photo') {
    const body = {
      chat_id: chatId,
      photo: data.file_id
    };

    if (data.caption) {
      body.caption = data.caption;
    }

    if (keyboard) {
      body.reply_markup = keyboard;
    }

    output.push({
      json: {
        api_method: 'sendPhoto',
        body
      }
    });

    continue;
  }

  // Telegram video circle / video note
  if (messageType === 'video_note') {
    const body = {
      chat_id: chatId,
      video_note: data.file_id
    };

    if (keyboard) {
      body.reply_markup = keyboard;
    }

    output.push({
      json: {
        api_method: 'sendVideoNote',
        body
      }
    });

    continue;
  }

  // Regular video
  if (messageType === 'video') {
    const body = {
      chat_id: chatId,
      video: data.file_id
    };

    const caption = data.caption || data.content;
    if (caption && caption !== '[video]') {
      body.caption = caption;
    }

    if (keyboard) {
      body.reply_markup = keyboard;
    }

    output.push({
      json: {
        api_method: 'sendVideo',
        body
      }
    });

    continue;
  }

  // Voice
  if (messageType === 'voice') {
    const body = {
      chat_id: chatId,
      voice: data.file_id
    };

    if (keyboard) {
      body.reply_markup = keyboard;
    }

    output.push({
      json: {
        api_method: 'sendVoice',
        body
      }
    });

    continue;
  }

  // Audio
  if (messageType === 'audio') {
    const body = {
      chat_id: chatId,
      audio: data.file_id
    };

    if (displayName && displayName !== '[audio]') {
      body.caption = displayName;
    }

    if (keyboard) {
      body.reply_markup = keyboard;
    }

    output.push({
      json: {
        api_method: 'sendAudio',
        body
      }
    });

    continue;
  }

  // Document / any other file
  if (messageType === 'document') {
    const body = {
      chat_id: chatId,
      document: data.file_id
    };

    if (displayName) {
      body.caption = displayName;
    }

    if (keyboard) {
      body.reply_markup = keyboard;
    }

    output.push({
      json: {
        api_method: 'sendDocument',
        body
      }
    });

    continue;
  }

  // Fallback for unknown file types
  const body = {
    chat_id: chatId,
    text: `📎 ${displayName}`
  };

  if (keyboard) {
    body.reply_markup = keyboard;
  }

  output.push({
    json: {
      api_method: 'sendMessage',
      body
    }
  });
}

return output;

const trigger = $('Telegram Trigger').first().json;
const msg = trigger.message;

if (!msg) {
  throw new Error('No Telegram message found in Telegram Trigger');
}

const userId = msg.from.id;
const chatId = msg.chat.id;

function basePayload(extra = {}) {
  return {
    user_id: userId,
    chat_id: chatId,

    message: null,
    content: null,
    message_type: 'text',

    file_id: null,
    file_unique_id: null,
    file_name: null,
    mime_type: null,
    caption: null,
    telegram_file_path: null,
    file_url: null,

    latitude: null,
    longitude: null,
    location_title: null,
    location_address: null,
    maps_url: null,

    ...extra
  };
}

// Text
if (msg.text) {
  return [
    {
      json: basePayload({
        message_type: 'text',
        message: msg.text,
        content: msg.text
      })
    }
  ];
}

// Location
if (msg.location) {
  const lat = msg.location.latitude;
  const lon = msg.location.longitude;
  const mapsUrl = `https://maps.google.com/?q=${lat},${lon}`;

  return [
    {
      json: basePayload({
        message_type: 'location',
        message: `Shared location: ${mapsUrl}`,
        content: `Shared location: ${mapsUrl}`,
        latitude: lat,
        longitude: lon,
        location_title: msg.venue?.title || null,
        location_address: msg.venue?.address || null,
        maps_url: mapsUrl
      })
    }
  ];
}

// Venue
// Telegram venue usually also contains location
if (msg.venue) {
  const lat = msg.venue.location.latitude;
  const lon = msg.venue.location.longitude;
  const mapsUrl = `https://maps.google.com/?q=${lat},${lon}`;

  return [
    {
      json: basePayload({
        message_type: 'location',
        message: `Shared venue: ${msg.venue.title || 'Location'}\n${mapsUrl}`,
        content: `Shared venue: ${msg.venue.title || 'Location'}\n${mapsUrl}`,
        latitude: lat,
        longitude: lon,
        location_title: msg.venue.title || null,
        location_address: msg.venue.address || null,
        maps_url: mapsUrl
      })
    }
  ];
}

// Video note / Telegram circle video
if (msg.video_note) {
  return [
    {
      json: basePayload({
        message_type: 'video_note',
        message: '[video note]',
        content: '[video note]',
        file_id: msg.video_note.file_id,
        file_unique_id: msg.video_note.file_unique_id,
        mime_type: 'video/mp4',
        caption: null
      })
    }
  ];
}


// Photo
if (msg.photo && msg.photo.length > 0) {
  const photo = msg.photo[msg.photo.length - 1];

  return [
    {
      json: basePayload({
        message_type: 'photo',
        message: msg.caption || '[photo]',
        content: msg.caption || '[photo]',
        file_id: photo.file_id,
        file_unique_id: photo.file_unique_id,
        caption: msg.caption || null
      })
    }
  ];
}

// Document / file
if (msg.document) {
  return [
    {
      json: basePayload({
        message_type: 'document',
        message: msg.caption || msg.document.file_name || '[document]',
        content: msg.caption || msg.document.file_name || '[document]',
        file_id: msg.document.file_id,
        file_unique_id: msg.document.file_unique_id,
        file_name: msg.document.file_name || null,
        mime_type: msg.document.mime_type || null,
        caption: msg.caption || null
      })
    }
  ];
}

// Voice
if (msg.voice) {
  return [
    {
      json: basePayload({
        message_type: 'voice',
        message: msg.caption || '[voice message]',
        content: msg.caption || '[voice message]',
        file_id: msg.voice.file_id,
        file_unique_id: msg.voice.file_unique_id,
        mime_type: msg.voice.mime_type || 'audio/ogg',
        caption: msg.caption || null
      })
    }
  ];
}

// Audio
if (msg.audio) {
  return [
    {
      json: basePayload({
        message_type: 'audio',
        message: msg.caption || msg.audio.file_name || msg.audio.title || '[audio]',
        content: msg.caption || msg.audio.file_name || msg.audio.title || '[audio]',
        file_id: msg.audio.file_id,
        file_unique_id: msg.audio.file_unique_id,
        file_name: msg.audio.file_name || msg.audio.title || null,
        mime_type: msg.audio.mime_type || null,
        caption: msg.caption || null
      })
    }
  ];
}

// Video
if (msg.video) {
  return [
    {
      json: basePayload({
        message_type: 'video',
        message: msg.caption || '[video]',
        content: msg.caption || '[video]',
        file_id: msg.video.file_id,
        file_unique_id: msg.video.file_unique_id,
        mime_type: msg.video.mime_type || 'video/mp4',
        caption: msg.caption || null
      })
    }
  ];
}

// Fallback
return [
  {
    json: basePayload({
      message_type: 'unknown',
      message: '[unrecognized message]',
      content: '[unrecognized message]'
    })
  }
];

