const items = $input.all();
const output = [];

// Функция форматирования текста (твоя исходная логика)
function formatMessageText(msg) {
  const type = msg.message_type || 'text';

  if (type === 'location') {
    const title = msg.location_title ? `\n${msg.location_title}` : '';
    const address = msg.location_address ? `\n${msg.location_address}` : '';
    const coords = msg.latitude && msg.longitude ? `\nCoordinates: ${msg.latitude}, ${msg.longitude}` : '';
    const maps = msg.maps_url ? `\nGoogle Maps: ${msg.maps_url}` : '';
    return `📍 Location${title}${address}${coords}${maps}`;
  }

  if (type === 'photo') {
    return msg.caption || msg.content || '📷 Photo';
  }

  if (type === 'document') {
    return msg.file_name ? `📄 ${msg.file_name}` : (msg.content || '📄 Document');
  }

  if (type === 'voice') {
    return msg.content || '🎙 Voice message';
  }

  if (type === 'audio') {
    return msg.file_name ? `🎵 ${msg.file_name}` : (msg.content || '🎵 Audio');
  }

  if (type === 'video') {
    return msg.caption || msg.content || '🎬 Video';
  }

  return msg.content || msg.message || '[empty message]';
}

// Если сообщений в топике нет
if (items.length === 0 || !items[0].json.id) {
  const trigger = $('Telegram Trigger').first().json;
  const fallbackChatId = trigger.message?.chat?.id || trigger.callback_query?.message?.chat?.id;

  output.push({
    json: {
      api_method: 'sendMessage',
      body: {
        chat_id: fallbackChatId,
        text: 'This topic is empty 📭'
      }
    }
  });
  return output;
}

// Проходим по всем сообщениям и строим структуру для вызова Telegram API
for (const item of items) {
  const msg = item.json;
  const formattedText = formatMessageText(msg);

  output.push({
    json: {
      api_method: 'sendMessage',
      body: {
        chat_id: msg.chat_id,
        text: ` Formatted Message:\n\n${formattedText}`,
        reply_markup: {
          inline_keyboard: [
            [
