  voice: 'Voice message',
  audio: 'Audio file',
  video: 'Video',
  video_note: 'Video note',
  location: 'Location',
  unknown: 'Unknown message'
};

const humanType = humanTypeMap[messageType] || messageType;

const fileAnalysisJson = item.file_analysis_json || {};
const fileSummary = fileAnalysisJson.summary || item.file_analysis_summary || '';
const detectedType = fileAnalysisJson.detected_type || item.file_analysis_detected_type || '';
const suggestedTopics = Array.isArray(fileAnalysisJson.suggested_topics)
  ? fileAnalysisJson.suggested_topics.filter(Boolean)
  : [];

const keywords = Array.isArray(fileAnalysisJson.keywords)
  ? fileAnalysisJson.keywords.filter(Boolean)
  : [];

const extractedText = fileAnalysisJson.visible_or_extracted_text || '';

const parts = [];

parts.push(`Telegram message type: ${humanType}`);

if (item.message) {
  parts.push(`Message text: ${item.message}`);
}

if (item.content && item.content !== item.message) {
  parts.push(`Content: ${item.content}`);
}

if (item.caption) {
  parts.push(`Caption: ${item.caption}`);
}

if (item.file_name) {
  parts.push(`File name: ${item.file_name}`);
}

if (item.mime_type) {
  parts.push(`MIME type: ${item.mime_type}`);
}

if (item.file_analysis_status) {
  parts.push(`File analysis status: ${item.file_analysis_status}`);
}

if (fileSummary) {
  parts.push(`File summary: ${fileSummary}`);
}

if (detectedType) {
  parts.push(`Detected file type: ${detectedType}`);
}

if (suggestedTopics.length > 0) {
  parts.push(`Suggested topics from file analysis: ${suggestedTopics.join(', ')}`);
}

if (keywords.length > 0) {
  parts.push(`File keywords: ${keywords.join(', ')}`);
}

if (extractedText) {
  parts.push(`Extracted file text: ${String(extractedText).slice(0, 2000)}`);
}

if (item.file_analysis_text) {
  parts.push(`Full AI file analysis:\n${item.file_analysis_text}`);
}

if (item.location_title) {
  parts.push(`Location title: ${item.location_title}`);
}

if (item.location_address) {
  parts.push(`Location address: ${item.location_address}`);
}

